import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import AlertMessage from './shared/AlertMessage';
import LoadingSpinner from './shared/LoadingSpinner';

const VerifyCertificate = () => {
  const { certificateId } = useParams();
  const navigate = useNavigate();
  
  const [certificateNumber, setCertificateNumber] = useState(certificateId || '');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [certificate, setCertificate] = useState(null);
  const [verified, setVerified] = useState(false);
  
  const handleVerify = async (e) => {
    if (e) e.preventDefault();
    
    if (!certificateNumber) {
      setError('Please enter a certificate number');
      return;
    }
    
    setLoading(true);
    setError(null);
    setCertificate(null);
    setVerified(false);
    
    try {
      // Call the verification API
      const response = await axios.get(
        `http://localhost:5001/api/certificates/verify/${certificateNumber}`
      );
      
      // Process the response
      setCertificate(response.data);
      setVerified(true);
      
    } catch (err) {
      console.error('Certificate verification error:', err);
      setError(err.response?.data?.message || 'Certificate could not be verified');
      setVerified(false);
    } finally {
      setLoading(false);
    }
  };
  
  // Automatically verify if certificateId is provided in URL
  React.useEffect(() => {
    if (certificateId) {
      handleVerify();
    }
  }, [certificateId]);
  
  return (
    <div className="max-w-2xl mx-auto my-8 p-6 bg-white rounded-lg shadow-lg">
      <h2 className="text-2xl font-bold text-center text-blue-900 mb-6">Verify Certificate</h2>
      
      <form onSubmit={handleVerify} className="mb-6">
        <div className="mb-4">
          <label htmlFor="certificateNumber" className="block text-gray-700 font-medium mb-2">
            Certificate Number
          </label>
          <div className="flex">
            <input
              type="text"
              id="certificateNumber"
              value={certificateNumber}
              onChange={(e) => setCertificateNumber(e.target.value)}
              placeholder="Enter SIU certificate number"
              className="flex-1 px-3 py-2 border border-gray-300 rounded-l-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 bg-blue-900 text-white font-medium rounded-r-lg hover:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Verify
            </button>
          </div>
        </div>
      </form>
      
      {loading ? (
        <LoadingSpinner message="Verifying certificate..." />
      ) : error ? (
        <AlertMessage
          type="error"
          message={{
            title: "Verification Failed",
            details: error
          }}
        />
      ) : verified && certificate ? (
        <div className="bg-gray-50 p-6 rounded-lg border border-green-200">
          <div className="flex items-center mb-4">
            <div className="bg-green-100 p-2 rounded-full">
              <svg className="h-6 w-6 text-green-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h3 className="ml-3 text-lg font-semibold text-gray-900">Certificate Verified</h3>
          </div>
          
          <div className="grid grid-cols-1 gap-4 mb-6">
            <div>
              <p className="text-sm font-medium text-gray-500">Recipient Name</p>
              <p className="text-base font-semibold text-gray-900">{certificate.recipientName}</p>
            </div>
            
            <div>
              <p className="text-sm font-medium text-gray-500">Program</p>
              <p className="text-base font-semibold text-gray-900">{certificate.program}</p>
            </div>
            
            <div>
              <p className="text-sm font-medium text-gray-500">Certificate Number</p>
              <p className="text-base font-semibold text-gray-900">{certificate.certificateNumber}</p>
            </div>
            
            <div>
              <p className="text-sm font-medium text-gray-500">Issue Date</p>
              <p className="text-base font-semibold text-gray-900">
                {new Date(certificate.issueDate).toLocaleDateString()}
              </p>
            </div>
            
            <div>
              <p className="text-sm font-medium text-gray-500">Status</p>
              <p className={`text-base font-semibold ${
                certificate.status === 'issued' ? 'text-green-600' :
                certificate.status === 'revoked' ? 'text-red-600' : 'text-yellow-600'
              }`}>
                {certificate.status.charAt(0).toUpperCase() + certificate.status.slice(1)}
              </p>
            </div>
            
            <div>
              <p className="text-sm font-medium text-gray-500">Blockchain Verification</p>
              <p className="text-base font-semibold text-gray-700 break-all">{certificate.blockchainHash}</p>
            </div>
          </div>
          
          <div className="mt-6 text-center">
            <p className="text-sm text-gray-500">
              This certificate has been cryptographically verified and recorded on blockchain.
            </p>
          </div>
        </div>
      ) : (
        <div className="text-center py-8 text-gray-500">
          <p>Enter a certificate number to verify its authenticity.</p>
          <p className="mt-2 text-sm">Example: SIU-PR-2023-123456</p>
        </div>
      )}
    </div>
  );
};

export default VerifyCertificate;
